import { useMemo, useState } from 'react';

import Alert from '@mui/material/Alert';
import Button from '@mui/material/Button';
import Chip from '@mui/material/Chip';
import Grid from '@mui/material/Grid';
import Stack from '@mui/material/Stack';
import TextField from '@mui/material/TextField';

import useToast from 'app/providers/useToast';
import MainCard from 'components/MainCard';
import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import useRoleAccess from 'features/auth/useRoleAccess';
import apiClient from 'lib/http/apiClient';
import API_PATHS from 'lib/http/apiPaths';
import extractApiErrorMessage from 'utils/apiError';

export default function ImportsPage() {
  const { showToast } = useToast();
  const canRunImport = useRoleAccess('OPERADOR');
  const canViewJobs = useRoleAccess('ADMINISTRADOR');
  const [filePath, setFilePath] = useState('');
  const [sheets, setSheets] = useState('');
  const [dryRun, setDryRun] = useState(true);
  const [running, setRunning] = useState(false);

  const filters = useMemo(
    () => [
      {
        key: 'status',
        label: 'Estado',
        options: [
          { value: 'PENDING', label: 'Pending' },
          { value: 'RUNNING', label: 'Running' },
          { value: 'SUCCESS', label: 'Success' },
          { value: 'PARTIAL', label: 'Partial' },
          { value: 'FAILED', label: 'Failed' }
        ]
      }
    ],
    []
  );

  const runImport = async () => {
    if (!filePath.trim()) {
      showToast('Debes indicar file_path del Excel.', 'warning');
      return;
    }

    try {
      setRunning(true);
      await apiClient.post('/imports/jobs/run/', {
        file_path: filePath,
        dry_run: dryRun,
        sheets
      });
      showToast('Importacion enviada correctamente. Actualiza la tabla para ver resultados.', 'success');
    } catch (err) {
      showToast(extractApiErrorMessage(err, 'No se pudo ejecutar la importacion.'), 'error');
    } finally {
      setRunning(false);
    }
  };

  return (
    <Stack sx={{ gap: 2 }}>
      <MainCard title="Ejecutar importacion Excel">
        <Grid container spacing={2}>
          <Grid size={{ xs: 12, md: 6 }}>
            <TextField
              fullWidth
              label="Ruta archivo Excel (file_path)"
              value={filePath}
              onChange={(event) => setFilePath(event.target.value)}
              placeholder="C:\\ruta\\MAESTRO.xlsx"
            />
          </Grid>
          <Grid size={{ xs: 12, md: 4 }}>
            <TextField
              fullWidth
              label="Hojas (opcional, separadas por coma)"
              value={sheets}
              onChange={(event) => setSheets(event.target.value)}
              placeholder="Datos_Propietarios,RESIDENTES"
            />
          </Grid>
          <Grid size={{ xs: 12, md: 2 }} sx={{ display: 'flex', alignItems: 'center' }}>
            <Button variant={dryRun ? 'contained' : 'outlined'} onClick={() => setDryRun((prev) => !prev)} fullWidth>
              {dryRun ? 'Dry-run' : 'Real'}
            </Button>
          </Grid>
          <Grid size={12}>
            <Button variant="contained" onClick={runImport} disabled={running || !canRunImport}>
              {running ? 'Ejecutando...' : 'Lanzar importacion'}
            </Button>
          </Grid>
        </Grid>
      </MainCard>

      {canViewJobs ? (
        <CrudResourceModule
          title="Historial de importaciones"
          path={API_PATHS.importJobs}
          columns={[
            { key: 'source_file', label: 'Archivo' },
            { key: 'started_at', label: 'Inicio' },
            {
              key: 'status',
              label: 'Estado',
              render: (row) => (
                <Chip
                  size="small"
                  label={row.status}
                  color={row.status === 'SUCCESS' ? 'success' : row.status === 'FAILED' ? 'error' : 'warning'}
                />
              )
            },
            { key: 'total_inserted', label: 'Insertados' },
            { key: 'total_updated', label: 'Actualizados' },
            { key: 'total_errors', label: 'Errores' },
            { key: 'total_warnings', label: 'Warnings' }
          ]}
          fields={[]}
          canCreate={false}
          canEdit={false}
          canDelete={false}
          defaultOrdering="-started_at"
          extraFilters={filters}
        />
      ) : (
        <Alert severity="info">
          Tu rol puede ejecutar importaciones, pero el historial completo esta disponible solo para administradores.
        </Alert>
      )}
    </Stack>
  );
}
